detailConfig:
this.table({
    cellClassName: function({
        row,
        column,
        rowIndex,
        columnIndex
    }) {
        if ('操作' == column.label) {
            return 'cellName';
        } else if ('工程名称' == column.label) {
            return 'cellProjectName';
        }
    },
    columns: [{
            prop: 'projectname',
            label: '工程名称',
            align: "left",
            minWidth: '24%',
            type: '',
            columnKey: '',
            fixed: false,
            plugins: [{
                    pluginType: 'button',
                    type: '',
                    icon: 'el-icon-s-flag',
                    click: function(scope) {
                        if (scope.row) {
                            // 设置选中工程时空仓库GUID
                            $Variable.工程时空仓库GUID = scope.row.projectrepositoryguid;
                            // 触发设置当前工程变量改变执行
                            $Variable.setCurrentProject = !$Variable.setCurrentProject;
                        }
                    }
                },
                {
                    pluginType: 'text',
                    type: ''
                }
            ]
        },
        {
            prop: 'projectdesc',
            label: '描述',
            align: "left",
            minWidth: '30%',
            type: '',
            columnKey: '',
            fixed: false,
        },
        {
            prop: 'creationtime',
            label: '创建时间',
            align: "left",
            minWidth: '14%',
            type: '',
            columnKey: '',
            fixed: false,
        },
        {
            prop: 'lastupdatetime',
            label: '上次更新时间',
            align: "left",
            minWidth: '14%',
            type: '',
            columnKey: '',
            fixed: false,
        },
        {
            prop: '操作',
            label: '操作',
            align: "left",
            minWidth: '18%',
            type: '',
            columnKey: '',
            fixed: false,
            plugins: [{
                pluginType: 'button',
                text: '进入工程',
                type: 'text',
                click: function(scope) {
                    if (scope.row) {
                        // 设置选中工程信息
                        $Variable.工程时空仓库名称 = scope.row.projectrepositoryname;
                        $Variable.工程时空仓库ID = scope.row.projectrepositoryid;
                        $Variable.工程时空仓库GUID = scope.row.projectrepositoryguid;
                        $Variable.工程Root时空仓库名称 = scope.row.projectrootrepositoryname;
                        $Variable.工程Root时空仓库ID = scope.row.projectrootrepositoryid;
                        $Variable.工程Root时空仓库GUID = scope.row.projectrootrepositoryguid;
                        // 触发进入工程变量改变执行
                        $Variable.enterProject = !$Variable.enterProject;
                    }
                }
            }, {
                pluginType: 'button',
                text: '编辑',
                type: 'text',
                click: function(scope) {

                    debugger

                    if (scope.row) {
                        //页面名称
                        const pageName = "工程新建编辑_弹窗页面";
                        // 配置窗口 top 位置
                        let windowHeight = document.body.clientHeight;
                        let pageHeight = 269;
                        let topPX = "0px";
                        if ((windowHeight - pageHeight) > 0) {
                            topPX = String((windowHeight - pageHeight) / 2 - 100) + "px";
                        }
                        //配置项
                        const options = {
                            //页面展示类型：弹出式
                            type: 2,
                            //弹出式样式配置
                            styleOptions: {
                                header: false,
                                modal: true,
                                width: '400',
                                height: '269',
                                draggable: true,
                                maximizable: false,
                                top: topPX
                            },
                            variables: [{
                                name: "操作类型",
                                value: "编辑"
                            }, {
                                name: "spaceTimeObjectFullPath",
                                value: $Variable.配置时空对象全路径
                            }, {
                                name: "spaceTimeObjectName",
                                value: $Variable.配置后台对象名称
                            }, {
                                name: "cloudID",
                                value: $Variable.cloudID
                            }, {
                                name: '工程名称',
                                value: scope.row.projectname
                            }, {
                                name: '工程描述',
                                value: scope.row.projectdesc
                            }, {
                                name: '工程时空仓库GUID',
                                value: scope.row.projectrepositoryguid
                            }, {
                                name: '工程业务物拷贝ID',
                                value: scope.row.entitycopyid
                            }]
                        };

                        ShowChild(pageName, options, (res) => {
                            if ("submit" === res.eventName) {
                                CloseChild(pageName);
                                // 刷新工程目录列表
                                $Variable.refreshProjectList = !$Variable.refreshProjectList;
                            } else if ("cancel" === res.eventName) {
                                CloseChild(pageName);
                            }
                        });
                    }
                }
            }, {
                pluginType: 'button',
                text: '删除',
                type: 'text',
                click: function(scope) {

                    debugger

                    if (scope.row) {
                        //页面名称
                        const pageName = "工程删除_弹窗页面";
                        // 配置窗口 top 位置
                        let windowHeight = document.body.clientHeight;
                        let pageHeight = 208;
                        let topPX = "0px";
                        if ((windowHeight - pageHeight) > 0) {
                            topPX = String((windowHeight - pageHeight) / 2 - 100) + "px";
                        }
                        const options = {
                            //页面展示类型：弹出式
                            type: 2,
                            //弹出式样式配置
                            styleOptions: {
                                header: false,
                                modal: true,
                                width: '400',
                                height: '208',
                                draggable: true,
                                maximizable: false,
                                top: topPX
                            },
                            variables: [{
                                name: "spaceTimeObjectFullPath",
                                value: $Variable.配置时空对象全路径
                            }, {
                                name: "spaceTimeObjectName",
                                value: $Variable.配置后台对象名称
                            }, {
                                name: "cloudID",
                                value: $Variable.cloudID
                            }, {
                                name: '工程时空仓库名称',
                                value: scope.row.projectrepositoryname
                            }, {
                                name: '工程时空仓库GUID',
                                value: scope.row.projectrepositoryguid
                            }]
                        };

                        ShowChild(pageName, options, (res) => {
                            if ("submit" === res.eventName) {
                                CloseChild(pageName);
                                // 刷新工程目录列表
                                $Variable.refreshProjectList = !$Variable.refreshProjectList;
                            } else if ("cancel" === res.eventName) {
                                CloseChild(pageName);
                            }
                        });
                    }
                }
            }]
        },
    ],
    totalData: []
});
